#include <bits/stdc++.h>
using namespace std;
int n,m,ans=1e9;
char s[51][51];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=0;i<n;i++)
        cin>>s[i];
    for(int i=0;i<n-2;i++)
        for(int j=i+1;j<n-1;j++){
            int sum=0;
            for(int x=0;x<n;x++)
                for(int y=0;y<m;y++){
                    if(x<=i)
                        sum+=(s[x][y]!='W');
                    else if(x<=j)
                        sum+=(s[x][y]!='B');
                    else
                        sum+=(s[x][y]!='R');
                }
            ans=min(ans,sum);
        }
    printf("%d",ans);
    return 0;
}
